// ---- helpers (Go side) ----------------------------------------------

// initialTheme picks the theme attribute the server emits on first
// render. Inline JS in <head> may override (cookie / localStorage may
// disagree), but server-side default avoids a one-frame mismatch when
// the cookie says "light".
func initialTheme(t string) string {
	if t == "light" {
		return "light"
	}
	return "dark"
}

func isShellHidden(p LayoutProps) bool {
	return p.HideTopNav || p.Variant == "auth"
}

func pageTitle(p LayoutProps) string {
	if p.Title == "" {
		return "Boxland"
	}
	return p.Title + " — Boxland"
}

func projectName(p LayoutProps) string {
	if p.Project.Name == "" {
		return "my world"
	}
	return p.Project.Name
}

func countLabel(n int) string {
	if n < 0 {
		n = 0
	}
	return formatIntPad(n)
}

func countAttr(n int) string {
	if n < 0 {
		n = 0
	}
	return formatIntPad(n)
}

func draftLabel(n int) string {
	if n == 0 {
		return "no drafts"
	}
	if n == 1 {
		return "1 draft"
	}
	return formatIntPad(n) + " drafts"
}

func designerHandle(email string) string {
	for i, c := range email {
		if c == '@' {
			return email[:i]
		}
	}
	return email
}

func pinnedClass(active, kind string) string {
	if active == kind {
		return "bx-tree__item"
	}
	return "bx-tree__item"
}

func overflowLabel(total, shown int) string {
	if total <= shown {
		return "0"
	}
	return formatIntPad(total - shown)
}

// activeMatch returns a closure used by treeSection to mark the active
// item. Closure form keeps the call site readable in the templ.
func activeMatch(activeKind string, activeID int64, want string) func(int64) bool {
	if activeKind != want {
		return func(int64) bool { return false }
	}
	return func(id int64) bool { return id == activeID }
}

// tagWithV ensures version strings render with a leading `v`, so the
// chrome update pill always shows e.g. "v0.1.0 → v0.2.0" regardless
// of whether the upstream tag carried the prefix.
func tagWithV(s string) string {
	if s == "" {
		return s
	}
	if s[0] == 'v' || s[0] == 'V' {
		return s
	}
	return "v" + s
}

// formatIntPad is a tiny templ-safe int formatter that keeps the
// templates from importing strconv just for stringification.
func formatIntPad(n int) string {
	if n == 0 {
		return "0"
	}
	neg := n < 0
	if neg {
		n = -n
	}
	out := ""
	for n > 0 {
		d := byte(n % 10)
		out = string(rune('0'+d)) + out
		n /= 10
	}
	if neg {
		out = "-" + out
	}
	return out
}

// libraryTotal sums the four asset-library kinds. Used as the badge on
// the "Library" tree group head.
func libraryTotal(p ProjectInfo) int {
	return p.SpriteCount + p.TilemapCount + p.AudioCount + p.UIPanelCount
}

